// The chat widget posts JSON. Pull out the fields, and give the
// conversation a stable session id so the memory node can find it.
const body = $json.body || $json;
return [{
  json: {
    message: (body.message || '').toString().trim(),
    name: (body.name || '').toString().trim(),
    phone: (body.phone || body.tel || '').toString().trim(),
    email: (body.email || '').toString().trim().toLowerCase(),
    sessionId: body.sessionId || 'web-anonymous',
    source: body.source || 'investment-advisor-website'
  }
}];

// The widget expects { reply: "..." }. Never return the raw agent object.
const reply = $json.output || $json.text || $json.reply
  || 'Thank you. A licensed advisor will get back to you shortly.';
return [{ json: { reply } }];
